using BenchmarkDotNet.Attributes;
using BenchmarkDotNet.Configs;
using BenchmarkDotNet.Environments;
using BenchmarkDotNet.Jobs;
using BenchmarkDotNet.Running;
using TextAnalysis;

var config = DefaultConfig.Instance
    .AddJob(Job.Default.WithRuntime(CoreRuntime.Core90).AsBaseline())
    .AddJob(Job.Default.WithRuntime(CoreRuntime.Core100));

BenchmarkRunner.Run<TextAnalyzerBenchmarks>(config, args);

[MemoryDiagnoser]
public class TextAnalyzerBenchmarks
{
    private TextAnalyzer _analyzer = null!;

    private const string SampleText =
        "The quick brown fox jumps over the lazy dog. " +
        "A journey of a thousand miles begins with a single step. " +
        "To be or not to be that is the question. " +
        "All that glitters is not gold. " +
        "The only thing we have to fear is fear itself. " +
        "In the middle of difficulty lies opportunity. " +
        "Life is what happens when you are busy making other plans. " +
        "The greatest glory in living lies not in never falling but in rising every time we fall.";

    [GlobalSetup]
    public void Setup()
    {
        _analyzer = new TextAnalyzer(SampleText);
    }

    [Benchmark]
    public double AverageWordLength() => _analyzer.AverageWordLength();

    [Benchmark]
    public object WordLengthHistogram() => _analyzer.WordLengthHistogram();

    [Benchmark]
    public int UniqueWordCount() => _analyzer.UniqueWordCount();
}

